const express = require('express');
const axios = require('axios');
const jwt = require('jsonwebtoken');
const app = express();
const port = 3000;

// OIDC provider configuration
const oidcConfig = {
  issuer: 'https://your-oidc-provider.com',
  clientId: 'your-client-id',
  clientSecret: 'your-client-secret',
  redirectUri: 'http://localhost:3000/callback'
};

app.use(express.urlencoded({ extended: true }));

// Route to handle the authorization request
app.get('/login', (req, res) => {
  const authUrl = `${oidcConfig.issuer}/authorize?response_type=code&client_id=${oidcConfig.clientId}&redirect_uri=${encodeURIComponent(oidcConfig.redirectUri)}&scope=openid email profile`;
  res.redirect(authUrl);
});

// Route to handle the authorization callback
app.get('/callback', async (req, res) => {
  const { code } = req.query;

  try {
    // Exchange authorization code for tokens
    const tokenResponse = await axios.post(`${oidcConfig.issuer}/token`, null, {
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      params: {
        grant_type: 'authorization_code',
        client_id: oidcConfig.clientId,
        client_secret: oidcConfig.clientSecret,
        redirect_uri: oidcConfig.redirectUri,
        code
      }
    });

    const { id_token } = tokenResponse.data;

    // Decode the JWT to extract user information
    const decodedToken = jwt.decode(id_token, { complete: true });
    if (!decodedToken || !decodedToken.payload) {
      return res.status(401).send('Invalid ID Token');
    }

    const { sub, email, name } = decodedToken.payload;

    // Create a user session
    req.session.user = {
      sub,
      email,
      name
    };

    res.send(`Welcome, ${name}!`);
  } catch (error) {
    console.error('Error exchanging code for tokens:', error);
    res.status(500).send('Internal Server Error');
  }
});

// Middleware to check if the user is authenticated
function isAuthenticated(req, res, next) {
  if (req.session.user) {
    return next();
  } else {
    res.status(401).send('Unauthorized');
  }
}

// Protected route
app.get('/profile', isAuthenticated, (req, res) => {
  const { sub, email, name } = req.session.user;
  res.send(`Profile: ${name}, Email: ${email}`);
});

app.listen(port, () => {
  console.log(`Server running at http://localhost:${port}`);
});